const feed = $input.first().json;
const staticData = this.getWorkflowStaticData('global');
staticData.threatFeed  = JSON.stringify(feed);
staticData.lastUpdated = feed.generated_at;
return [{ json: { success: true, item_count: feed.items.length, generated_at: feed.generated_at } }];

const staticData = this.getWorkflowStaticData('global');
const raw = staticData.threatFeed;

if (!raw) {
  return [{ json: {
    generated_at: new Date().toISOString(),
    expires_at:   new Date().toISOString(),
    live_count: 0, static_count: 0, fallback: true,
    items: [
      { icon:'accent', text:'Average breach cost: $4.88M USD — IBM 2024',             source:'static', category:'stat'   },
      { icon:'warn',   text:'74% of orgs lack a tested incident response plan',        source:'static', category:'stat'   },
      { icon:'ok',     text:'Avg TTX exercise reduces IR time by 40%',                 source:'static', category:'hexius' },
      { icon:'accent', text:'Mean time to identify a breach: 194 days (industry avg)', source:'ibm',   category:'stat'   },
      { icon:'warn',   text:'60% of SMEs close within 6 months of a cyberattack',      source:'static', category:'stat'   },
      { icon:'accent', text:'83% of breaches involve a human element — Verizon DBIR',  source:'verizon',category:'stat'   }
    ]
  }}];
}

return [{ json: JSON.parse(raw) }];
